// Recibe { id, status?, notes?, historyEntry? } — id es q.id (BIGINT) ó string 'r_<id>'.
// Devuelve { ok, quoteId, status, payload, history }.
const src = $input.first().json;
const body = src.body || src;
let rawId = body.id;
if (typeof rawId === 'string' && rawId.startsWith('r_')) rawId = rawId.slice(2);
const quoteId = Number(rawId);
if (!Number.isFinite(quoteId) || quoteId <= 0) {
  throw new Error('id de cotización inválido');
}
const allowed = ['nuevo','contactado','propuesta','negociacion','ganada','perdida','archivada'];
let status = body.status;
if (status != null) {
  status = String(status).trim().toLowerCase();
  if (!allowed.includes(status)) throw new Error('status inválido: ' + status);
}
const notes = body.notes != null ? String(body.notes) : null;
const historyEntry = body.historyEntry || null; // { at, by, fromStatus, toStatus, note }
return [{ json: { quoteId, status, notes, historyEntry } }];

// Merge: status (top-level + payload), notes (payload), history (payload.history[]).
const input = $('Validate input').first().json;
const current = $input.first().json;
if (!current || !current.id) throw new Error('cotización no encontrada');
const payload = current.payload && typeof current.payload === 'object' ? { ...current.payload } : {};
const nextStatus = input.status || current.status || 'nuevo';
if (input.notes != null) payload.notes = input.notes;
if (input.status && input.status !== current.status) {
  payload.history = Array.isArray(payload.history) ? [...payload.history] : [];
  payload.history.push({
    at: new Date().toISOString(),
    fromStatus: current.status,
    toStatus: input.status,
    note: input.historyEntry?.note || null,
    by: input.historyEntry?.by || 'admin',
  });
}
if (input.historyEntry && !input.status) {
  payload.history = Array.isArray(payload.history) ? [...payload.history] : [];
  payload.history.push({
    at: new Date().toISOString(),
    note: input.historyEntry.note || null,
    by: input.historyEntry.by || 'admin',
  });
}
payload.status = nextStatus;
return [{ json: { quoteId: current.id, nextStatus, payloadJson: JSON.stringify(payload) } }];
